// Index maps for O(1) lookup
export const BY_SLUG = Object.fromEntries(
  ELEMENT_CONTENT.map(e => [`${e.typeSlug}/${e.slug}`, e])
);

export const BY_TYPE = ELEMENT_CONTENT.reduce((acc, e) => {
  if (!acc[e.typeSlug]) acc[e.typeSlug] = [];
  acc[e.typeSlug].push(e);
  return acc;
}, {} as Record<string, ElementContent[]>);

